
"use client";

import { useState, useEffect, useTransition } from 'react';
import { getVendors, type Vendor } from '@/ai/flows/vendor-flow';
import { AddNewVendorCard } from '@/components/admin/AddNewVendorCard';
import { VendorListCard } from '@/components/admin/VendorListCard';
import { PublishOrderCard } from '@/components/admin/PublishOrderCard';
import { useRouter } from 'next/navigation';
import { SiteHeader } from '@/components/SiteHeader';

// This is now a Client Component again to handle state and actions
export default function AdminPage() {
  const [vendors, setVendors] = useState<Vendor[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const router = useRouter();

  const fetchVendors = async () => {
    setIsLoading(true);
    try {
      const fetchedVendors = await getVendors();
      setVendors(fetchedVendors);
    } catch (error) {
      console.error("讀取店家資料失敗:", error);
      // Optionally, show a toast message to the user
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchVendors();
  }, []);

  const handleVendorChange = () => {
    fetchVendors();
    router.refresh();
  }


  return (
    <div className="min-h-screen bg-background font-body text-foreground">
      <SiteHeader />
      <main className="container mx-auto p-4 sm:p-6 lg:p-8">
        <h1 className="font-headline text-3xl font-bold mb-6">管理介面</h1>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          <PublishOrderCard vendors={vendors.filter(v => v.isActive)} />
          <AddNewVendorCard onVendorAdded={handleVendorChange} />
          <VendorListCard initialVendors={vendors} onVendorsChange={handleVendorChange} />
        </div>
      </main>
    </div>
  );
}
